import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void insertInMiddle() {
        // [1,3,5,7] — 4 goes between index 1 (value 3) and index 2 (value 5)
        assertEquals(2, new Solution().insertionPoint(new int[]{1, 3, 5, 7}, 4));
    }

    @Test
    void insertBeforeAll() {
        // 0 is smaller than every element
        assertEquals(0, new Solution().insertionPoint(new int[]{1, 3, 5, 7}, 0));
    }

    @Test
    void insertAfterAll() {
        // 8 is larger than every element — insertion index equals array length
        assertEquals(4, new Solution().insertionPoint(new int[]{1, 3, 5, 7}, 8));
    }

    @Test
    void targetAlreadyPresent() {
        // 5 is at index 2; return its existing index
        assertEquals(2, new Solution().insertionPoint(new int[]{1, 3, 5, 7}, 5));
    }

    @Test
    void emptyArray() {
        // Inserting into empty array always returns 0
        assertEquals(0, new Solution().insertionPoint(new int[]{}, 3));
    }

    @Test
    void singleElementTargetPresent() {
        assertEquals(0, new Solution().insertionPoint(new int[]{10}, 10));
    }

    @Test
    void singleElementTargetAbsent() {
        // 15 > 10, so insertion index is 1
        assertEquals(1, new Solution().insertionPoint(new int[]{10}, 15));
    }
}
